// 원본 테마 여러 개의 id를 하나로 합치는 헬퍼
function _pick(...names) {
  const seen = new Set();
  names.forEach(n => {
    const t = _RAW_THEMES.find(x => x.name === n);
    if (t) t.ids.forEach(id => seen.add(id));
  });
  return [...seen];
}

